import pandas as pd
from sklearn.preprocessing import StandardScaler
from sklearn.decomposition import PCA

def task_func(data, n_components=2):
    if not isinstance(data, pd.DataFrame) or data.isnull().values.any():
        raise ValueError("Input DataFrame is either not provided or contains non-numeric data.")

    if len(data.columns) <= n_components:
        raise ValueError("n_components must be less than the number of columns in the data.")

    sc = StandardScaler()
    scaled_data = pd.DataFrame(sc.fit_transform(data), columns=data.columns)

    pca = PCA(n_components=n_components)
    pca_df = pd.DataFrame(pca.fit_transform(scaled_data), columns=['PC'+str(i) for i in range(1, n_components+1)])

    return tuple(pca_df)
